'use client';

import { useState, useEffect } from 'react';
import { Card, Pack } from '@/types/card';
import { CardGenerator } from '@/lib/card-generator';
import { Button } from '@/components/Button';
import { Card as CardComponent } from '@/components/Card';

export default function Home() {
  const [generatedCard, setGeneratedCard] = useState<Card | null>(null);
  const [pack, setPack] = useState<Pack | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showPack, setShowPack] = useState(false);

  const handleGenerateCard = async () => {
    setIsGenerating(true);
    try {
      const card = await CardGenerator.generateCard(Date.now());
      setGeneratedCard(card);
    } catch (error) {
      console.error('Error generating card:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGeneratePack = async () => {
    setIsGenerating(true);
    try {
      const newPack = await CardGenerator.generatePack();
      setPack(newPack);
      setShowPack(true);
    } catch (error) {
      console.error('Error generating pack:', error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <main className="min-h-screen bg-gradient-to-br from-purple-900 via-blue-900 to-indigo-900">
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-5xl font-bold text-white mb-4">
            AI Monsters
          </h1>
          <p className="text-xl text-gray-300 mb-8">
            A 2D card game where every card is AI-generated and unique
          </p>
          <div className="flex justify-center gap-4">
            <Button 
              variant="primary" 
              onClick={handleGenerateCard}
              disabled={isGenerating}
            >
              {isGenerating ? 'Generating...' : 'Generate Card'}
            </Button>
            <Button 
              variant="secondary" 
              onClick={handleGeneratePack}
              disabled={isGenerating}
            >
              {isGenerating ? 'Generating...' : 'Open Pack'}
            </Button>
          </div>
        </div>

        {/* Single Card Generation */}
        <div className="mb-16">
          <h2 className="text-3xl font-bold text-white text-center mb-8">
            Generate a Single Card
          </h2>
          <div className="flex justify-center">
            {generatedCard ? (
              <CardComponent 
                key={generatedCard.id}
                name={generatedCard.name}
                description={generatedCard.description}
                attack={generatedCard.attack}
                defense={generatedCard.defense}
                range={generatedCard.range}
                rarity={generatedCard.rarity}
                type={generatedCard.card_type}
                imageUrl={generatedCard.image_url}
              />
            ) : (
              <div className="w-96 h-128 bg-gray-800 rounded-lg border-2 border-dashed border-gray-600 flex items-center justify-center">
                <p className="text-gray-400 text-center">
                  Click "Generate Card" to create a unique AI card
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Pack Opening */}
        <div className="mb-16">
          <h2 className="text-3xl font-bold text-white text-center mb-8">
            Card Pack
          </h2>
          {pack && (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 max-w-6xl mx-auto">
              {pack.cards.map((card, index) => (
                <div 
                  key={`${card.id}-${index}`}
                  className={`transform transition-all duration-500 ${
                    showPack ? 'scale-100 opacity-100' : 'scale-50 opacity-0'
                  }`}
                  style={{ transitionDelay: `${index * 100}ms` }}
                >
                  <CardComponent 
                    name={card.name}
                    description={card.description}
                    attack={card.attack}
                    defense={card.defense}
                    range={card.range}
                    rarity={card.rarity}
                    type={card.card_type}
                    imageUrl={card.image_url}
                  />
                </div>
              ))}
            </div>
          )}
          {!pack && (
            <div className="flex justify-center">
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 max-w-6xl mx-auto">
                {[...Array(7)].map((_, index) => (
                  <div 
                    key={index}
                    className="w-full h-48 bg-gray-800 rounded-lg border-2 border-dashed border-gray-600 flex items-center justify-center"
                  >
                    <p className="text-gray-400 text-center">
                      Card {index + 1}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

         {/* Sample Cards Display */}
        <div className="mb-16">
          <h2 className="text-3xl font-bold text-white text-center mb-8">
            AI-Generated Card Gallery ✨
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 max-w-6xl mx-auto">
            <CardComponent 
              name="Fire Dragon" 
              description="A majestic dragon that breathes scorching flames, scales shimmering with molten intensity"
              attack={85} 
              defense={60} 
              range={2}
              rarity="Legendary"
              type="Unit"
              imageUrl="https://via.placeholder.com/832x1248/FF6B35/FFFFFF?text=Fire+Dragon"
            />
            <CardComponent 
              name="Wizard" 
              description="A mystical wizard casting arcane spells, mystical symbols floating around ancient staff"
              attack={45} 
              defense={40} 
              range={3}
              rarity="Rare"
              type="Unit"
              imageUrl="https://via.placeholder.com/832x1248/6B46FF/FFFFFF?text=Wizard"
            />
            <CardComponent 
              name="Lightning Bolt" 
              description="A powerful spell that crackles with electrical energy, striking from stormy skies above"
              attack={70} 
              defense={0} 
              range={4}
              rarity="Epic"
              type="Spell"
              imageUrl="https://via.placeholder.com/832x1248/FFD700/000000?text=Lightning"
            />
            <CardComponent 
              name="Castle Tower" 
              description="A sturdy defensive fortress with stone walls and defensive archers, protecting the realm"
              attack={0} 
              defense={120} 
              range={2}
              rarity="Rare"
              type="Building"
              imageUrl="https://via.placeholder.com/832x1248/8B4513/FFFFFF?text=Castle"
            />
          </div>
          
          {/* Status Indicators */}
          <div className="mt-12 text-center">
            <div className="inline-flex items-center gap-6 bg-white/10 backdrop-blur-sm rounded-lg px-6 py-4">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-white text-sm">AI Art Generation: ✅ ACTIVE</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-green-500 rounded-full animate-pulse"></div>
                <span className="text-white text-sm">Card Generation: ✅ WORKING</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 bg-yellow-500 rounded-full animate-pulse"></div>
                <span className="text-white text-sm">SpacetimeDB: ⏳ PENDING</span>
              </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="text-center text-gray-400">
          <p>Every card is unique and AI-generated. No two cards are the same!</p>
        </div>
      </div>
    </main>
  );
}